import { z } from "zod";

export const checkoutRequestSchema = z.object({
  plan: z.enum(["starter", "pro", "enterprise"]),
  interval: z.enum(["month", "year"]).optional().default("month"),
  teamId: z.string().optional(),
  successUrl: z.string().url(),
  cancelUrl: z.string().url(),
});

export const portalRequestSchema = z.object({
  returnUrl: z.string().url(),
});

export const validateIapRequestSchema = z.object({
  platform: z.enum(["ios", "android"]),
  receiptData: z.string(),
  productId: z.string(),
});

export const restorePurchasesRequestSchema = z.object({
  platform: z.enum(["ios", "android"]),
  appUserId: z.string(),
});

export type CheckoutRequest = z.infer<typeof checkoutRequestSchema>;
export type PortalRequest = z.infer<typeof portalRequestSchema>;
export type ValidateIapRequest = z.infer<typeof validateIapRequestSchema>;
export type RestorePurchasesRequest = z.infer<typeof restorePurchasesRequestSchema>;
